use std::fmt;

#[derive(Debug, Clone, PartialEq)]
pub enum ChangeKind {
    Added,
    Removed,
    Context,
}

pub struct Change {
    pub kind: ChangeKind,
    pub content: String,
}

impl fmt::Display for Change {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let prefix = match self.kind { ChangeKind::Added => '+', ChangeKind::Removed => '-', ChangeKind::Context => ' ' };
        write!(f, "{}{}", prefix, self.content)
    }
}

