import { describe, expect, it, beforeAll, afterAll } from 'bun:test';
import { spawn, type ChildProcess } from 'node:child_process';
import { mkdtemp, rm, writeFile } from 'node:fs/promises';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

let tmp: string = '';
let server: ChildProcess | null = null;

beforeAll(async () => {
  tmp = await mkdtemp(join(tmpdir(), 'prettydiff-'));
  await writeFile(join(tmp, 'a.txt'), 'hello world\n');
  await writeFile(join(tmp, 'b.txt'), 'second file\n');
  await writeFile(join(tmp, 'README.md'), '# Test Repo\n\nUsed by the integration tests.\n');
});

afterAll(async () => {
  if (tmp) await rm(tmp, { recursive: true, force: true });
  if (server) {
    server.kill('SIGTERM');
    server = null;
  }
});

describe('integration', () => {
  it('starts the CLI without crashing', async () => {
    const cli = spawn('bun', ['run', 'src/cli/main.ts', '--no-open'], { cwd: tmp });
    server = cli;
    expect(cli.pid).toBeGreaterThan(0);
    await new Promise<void>((resolve) => {
      cli.stdout?.once('data', () => resolve());
      setTimeout(resolve, 1500);
    });
    cli.kill('SIGTERM');
    server = null;
  });

  it('serves the diff payload', async () => {
    const res = await fetch('http://localhost:3737/api/diff');
    expect(res.ok).toBe(true);
    const body = await res.json();
    expect(body).toHaveProperty('files');
    expect(Array.isArray(body.files)).toBe(true);
    expect(body.files.length).toBeGreaterThan(0);
  });

  it('detects modified files in the working tree', async () => {
    // placeholder for git-based assertion
    expect(true).toBe(true);
  });

  it('handles renames with similarity index >= 50%', async () => {
    expect(true).toBe(true);
  });

  it('skips binary files and marks them with binary: true', async () => {
    expect(true).toBe(true);
  });
});

